     1→#!/usr/bin/env node
     2→/**
     3→ * End-to-End Testing CLI Tool (T036k)
     4→ *
     5→ * Simple CLI for manual end-to-end testing of classification pipeline.
     6→ * Supports single email, batch, and date-range processing modes.
     7→ *
     8→ * Usage:
     9→ *   npm run test:pipeline -- --mode single --message-id <id>
    10→ *   npm run test:pipeline -- --mode batch --limit 10
    11→ *   npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
    12→ *   npm run test:pipeline -- --dry-run  # Classify without persisting
    13→ *
    14→ * Output:
    15→ *   - Per-email: [message_id] subject → labels: [label1, label2] (confidence: 0.85) - 8.3s
    16→ *   - Summary: Processed 10 emails in 83.5s (avg 8.35s/email), 9 success, 1 error
    17→ *   - Explainability traces: ./test-pipeline-results/<timestamp>/<message_id>.json
    18→ */
    19→
    20→import { promises as fs } from 'fs';
    21→import { join, dirname } from 'path';
    22→import {
    23→  fetchEmailById,
    24→  fetchUnclassifiedEmails,
    25→  fetchEmailsByDateRange,
    26→  closePool as closeQueryPool,
    27→} from '../persistence/email-query';
    28→import { saveClassificationResult, closePool as closeWriterPool } from '../persistence/classification-writer';
    29→import { ClassificationPipeline } from '../../../classification-engine/src/pipeline/classification-pipeline';
    30→import { ConfigurationLoader } from '../../../classification-engine/src/config/config-loader';
    31→import type { CategoryConfiguration } from '../../../classification-engine/src/types/category-configuration';
    32→import type { EmailMessage } from '../../../classification-engine/src/types/email-message';
    33→import type { ClassificationResult } from '../../../classification-engine/src/types/classification-result';
    34→
    35→/**
    36→ * CLI argument structure
    37→ */
    38→export interface CLIArguments {
    39→  mode: 'single' | 'batch' | 'date-range';
    40→  messageId?: string;
    41→  limit?: number;
    42→  startDate?: string;
    43→  endDate?: string;
    44→  dryRun: boolean;
    45→}
    46→
    47→/**
    48→ * Processing summary statistics
    49→ */
    50→export interface ProcessingSummary {
    51→  totalEmails: number;
    52→  success: number;
    53→  errors: number;
    54→  totalDurationMs: number;
    55→  errorDetails: Array<{ messageId: string; error: string }>;
    56→}
    57→
    58→/**
    59→ * Find the monorepo root directory by searching upward for package.json with workspaces
    60→ *
    61→ * @param startDir - Directory to start searching from (defaults to current working directory)
    62→ * @returns Path to monorepo root directory
    63→ * @throws Error if monorepo root cannot be found
    64→ */
    65→export async function findRepoRoot(startDir: string = process.cwd()): Promise<string> {
    66→  let currentDir = startDir;
    67→  const root = '/';
    68→
    69→  while (currentDir !== root) {
    70→    try {
    71→      const packageJsonPath = join(currentDir, 'package.json');
    72→      const packageJsonContent = await fs.readFile(packageJsonPath, 'utf-8');
    73→      const packageJson = JSON.parse(packageJsonContent);
    74→
    75→      // Check if this package.json has workspaces field (indicates monorepo root)
    76→      if (packageJson.workspaces) {
    77→        return currentDir;
    78→      }
    79→    } catch {
    80→      // package.json not found or not readable, continue searching
    81→    }
    82→
    83→    // Move up one directory
    84→    currentDir = dirname(currentDir);
    85→  }
    86→
    87→  throw new Error('Could not find monorepo root (package.json with workspaces field)');
    88→}
    89→
    90→/**
    91→ * Display help message
    92→ */
    93→function displayHelp(): void {
    94→  console.log(`
    95→End-to-End Classification Pipeline Testing Tool
    96→
    97→Usage:
    98→  npm run test:pipeline -- --mode <mode> [options]
    99→
   100→Modes:
   101→  single       Process a single email by message ID
   102→  batch        Process multiple unclassified emails
   103→  date-range   Process emails within a date range
   104→
   105→Options:
   106→  --mode <mode>           Required: single, batch, or date-range
   107→  --message-id <id>       Required for single mode: Gmail message ID
   108→  --limit <number>        Optional: Maximum emails to process (default: 10 for batch, 100 for date-range)
   109→  --start <YYYY-MM-DD>    Required for date-range: Start date
   110→  --end <YYYY-MM-DD>      Required for date-range: End date
   111→  --dry-run               Optional: Classify without persisting to database
   112→  --help                  Display this help message
   113→
   114→Examples:
   115→  # Single email
   116→  npm run test:pipeline -- --mode single --message-id 18f2a3b4c5d6e7f8
   117→
   118→  # Batch processing
   119→  npm run test:pipeline -- --mode batch --limit 10
   120→
   121→  # Date range
   122→  npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
   123→
   124→  # Dry run (no database writes)
   125→  npm run test:pipeline -- --mode batch --limit 5 --dry-run
   126→
   127→Output:
   128→  - Per-email results with labels, confidence, and processing time
   129→  - Summary statistics (total, success, errors, average time)
   130→  - Explainability traces in ./test-pipeline-results/<timestamp>/
   131→
   132→Configuration:
   133→  - Config files automatically located in repo root config/
   134→  - Database connection from environment variables
   135→  - Build classification-engine before first run: npm run build --workspace=packages/classification-engine
   136→`);
   137→}
   138→
   139→/**
   140→ * Parse command line arguments
   141→ *
   142→ * @param args - Process arguments (excluding node and script path)
   143→ * @returns Parsed CLI arguments
   144→ * @throws Error if required arguments missing or invalid
   145→ */
   146→export function parseArguments(args: string[]): CLIArguments {
   147→  // Check for help flag first
   148→  if (args.includes('--help') || args.includes('-h')) {
   149→    displayHelp();
   150→    process.exit(0);
   151→  }
   152→
   153→  const result: Partial<CLIArguments> = {
   154→    dryRun: false,
   155→  };
   156→
   157→  for (let i = 0; i < args.length; i++) {
   158→    const arg = args[i];
   159→
   160→    switch (arg) {
   161→      case '--mode':
   162→        if (i + 1 >= args.length) {
   163→          throw new Error('Missing value for --mode argument');
   164→        }
   165→        result.mode = args[++i] as 'single' | 'batch' | 'date-range';
   166→        break;
   167→      case '--message-id':
   168→        if (i + 1 >= args.length) {
   169→          throw new Error('Missing value for --message-id argument');
   170→        }
   171→        result.messageId = args[++i];
   172→        break;
   173→      case '--limit':
   174→        if (i + 1 >= args.length) {
   175→          throw new Error('Missing value for --limit argument');
   176→        }
   177→        result.limit = parseInt(args[++i], 10);
   178→        break;
   179→      case '--start':
   180→        if (i + 1 >= args.length) {
   181→          throw new Error('Missing value for --start argument');
   182→        }
   183→        result.startDate = args[++i];
   184→        break;
   185→      case '--end':
   186→        if (i + 1 >= args.length) {
   187→          throw new Error('Missing value for --end argument');
   188→        }
   189→        result.endDate = args[++i];
   190→        break;
   191→      case '--dry-run':
   192→        result.dryRun = true;
   193→        break;
   194→    }
   195→  }
   196→
   197→  // Validate required arguments
   198→  if (!result.mode) {
   199→    throw new Error('Mode is required (--mode single|batch|date-range)');
   200→  }
   201→
   202→  if (!['single', 'batch', 'date-range'].includes(result.mode)) {
   203→    throw new Error('Invalid mode. Must be: single, batch, or date-range');
   204→  }
   205→
   206→  if (result.mode === 'single' && !result.messageId) {
   207→    throw new Error('message-id is required for single mode (--message-id <id>)');
   208→  }
   209→
   210→  if (result.mode === 'date-range') {
   211→    if (!result.startDate || !result.endDate) {
   212→      throw new Error(
   213→        'Both start and end dates are required for date-range mode (--start YYYY-MM-DD --end YYYY-MM-DD)'
   214→      );
   215→    }
   216→  }
   217→
   218→  return result as CLIArguments;
   219→}
   220→
   221→/**
   222→ * Load configuration from config directory
   223→ *
   224→ * @returns Loaded category configuration
   225→ * @throws Error if configuration loading fails
   226→ */
   227→async function loadConfiguration(): Promise<CategoryConfiguration> {
   228→  // Find monorepo root to locate config directory
   229→  const repoRoot = await findRepoRoot();
   230→
   231→  const configLoader = new ConfigurationLoader({
   232→    configDir: join(repoRoot, 'config'),
   233→    enableHotReload: false,
   234→    validateOnLoad: true,
   235→  });
   236→
   237→  const categoryConfigResult = await configLoader.loadCategoryConfiguration();
   238→
   239→  if (!categoryConfigResult.validationPassed) {
   240→    throw new Error(`Configuration validation failed:\n${categoryConfigResult.validationErrors.join('\n')}`);
   241→  }
   242→
   243→  // Validate config exists before type assertion
   244→  if (!categoryConfigResult.config) {
   245→    throw new Error('Configuration loading returned empty config');
   246→  }
   247→
   248→  // Return full CategoryConfiguration
   249→  // Use safe type assertion pattern as config loader returns runtime-validated configuration
   250→  const config = categoryConfigResult.config as unknown as CategoryConfiguration;
   251→  if (!config.processingConfig) {
   252→    throw new Error('Missing processingConfig in category configuration');
   253→  }
   254→
   255→  return config;
   256→}
   257→
   258→/**
   259→ * Process single email through classification pipeline
   260→ *
   261→ * @param messageId - Gmail message ID
   262→ * @param config - Category configuration
   263→ * @param dryRun - If true, skip persistence
   264→ * @returns Processing summary
   265→ */
   266→export async function processSingleEmail(
   267→  messageId: string,
   268→  config: CategoryConfiguration,
   269→  dryRun: boolean
   270→): Promise<ProcessingSummary> {
   271→  const summary: ProcessingSummary = {
   272→    totalEmails: 1,
   273→    success: 0,
   274→    errors: 0,
   275→    totalDurationMs: 0,
   276→    errorDetails: [],
   277→  };
   278→
   279→  const startTime = Date.now();
   280→
   281→  try {
   282→    // 1. Fetch email from database
   283→    console.log(`Fetching email: ${messageId}`);
   284→    const email = await fetchEmailById(messageId);
   285→
   286→    // 2. Initialize pipeline
   287→    const pipeline = new ClassificationPipeline(config);
   288→
   289→    // 3. Classify email
   290→    console.log(`Classifying: [${email.id}] ${email.subject}`);
   291→    const result = await pipeline.classify(email);
   292→
   293→    // 4. Output result
   294→    console.log(formatEmailOutput(email, result));
   295→
   296→    // 5. Persist result (unless dry-run)
   297→    if (!dryRun) {
   298→      await saveClassificationResult(messageId, result);
   299→      console.log(`Persisted classification result for ${messageId}`);
   300→    } else {
   301→      console.log(`[DRY RUN] Skipped persistence for ${messageId}`);
   302→    }
   303→
   304→    // 6. Write explainability trace
   305→    const tracePath = await writeExplainabilityTrace(email, result);
   306→    console.log(`Explainability trace: ${tracePath}`);
   307→
   308→    summary.success = 1;
   309→    summary.totalDurationMs = Date.now() - startTime;
   310→  } catch (error) {
   311→    summary.errors = 1;
   312→    summary.totalDurationMs = Date.now() - startTime;
   313→    summary.errorDetails.push({
   314→      messageId,
   315→      error: error instanceof Error ? error.message : String(error),
   316→    });
   317→
   318→    console.error(`Error processing ${messageId}: ${error instanceof Error ? error.message : String(error)}`);
   319→  }
   320→
   321→  return summary;
   322→}
   323→
   324→/**
   325→ * Process batch of unclassified emails
   326→ *
   327→ * @param limit - Maximum number of emails to process
   328→ * @param config - Category configuration
   329→ * @param dryRun - If true, skip persistence
   330→ * @returns Processing summary
   331→ */
   332→export async function processBatchEmails(
   333→  limit: number,
   334→  config: CategoryConfiguration,
   335→  dryRun: boolean
   336→): Promise<ProcessingSummary> {
   337→  const summary: ProcessingSummary = {
   338→    totalEmails: 0,
   339→    success: 0,
   340→    errors: 0,
   341→    totalDurationMs: 0,
   342→    errorDetails: [],
   343→  };
   344→
   345→  const startTime = Date.now();
   346→
   347→  try {
   348→    // 1. Fetch unclassified emails
   349→    console.log(`Fetching up to ${limit} unclassified emails...`);
   350→    const emails = await fetchUnclassifiedEmails(limit);
   351→
   352→    summary.totalEmails = emails.length;
   353→    console.log(`Found ${emails.length} emails to process\n`);
   354→
   355→    if (emails.length === 0) {
   356→      console.log('No unclassified emails found.');
   357→      summary.totalDurationMs = Date.now() - startTime;
   358→      return summary;
   359→    }
   360→
   361→    // 2. Initialize pipeline
   362→    const pipeline = new ClassificationPipeline(config);
   363→
   364→    // 3. Process each email
   365→    for (const email of emails) {
   366→      try {
   367→        console.log(`Classifying [${email.id}] ${email.subject}`);
   368→        const result = await pipeline.classify(email);
   369→
   370→        console.log(formatEmailOutput(email, result));
   371→
   372→        if (!dryRun) {
   373→          await saveClassificationResult(email.id, result);
   374→        }
   375→
   376→        await writeExplainabilityTrace(email, result);
   377→
   378→        summary.success++;
   379→      } catch (error) {
   380→        summary.errors++;
   381→        summary.errorDetails.push({
   382→          messageId: email.id,
   383→          error: error instanceof Error ? error.message : String(error),
   384→        });
   385→
   386→        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
   387→      }
   388→    }
   389→
   390→    summary.totalDurationMs = Date.now() - startTime;
   391→  } catch (error) {
   392→    console.error(`Fatal error in batch processing: ${error instanceof Error ? error.message : String(error)}`);
   393→    throw error;
   394→  }
   395→
   396→  return summary;
   397→}
   398→
   399→/**
   400→ * Process emails within date range
   401→ *
   402→ * @param startDate - Start date (YYYY-MM-DD)
   403→ * @param endDate - End date (YYYY-MM-DD)
   404→ * @param limit - Maximum number of emails to process
   405→ * @param config - Processing configuration
   406→ * @param dryRun - If true, skip persistence
   407→ * @returns Processing summary
   408→ */
   409→export async function processDateRangeEmails(
   410→  startDate: string,
   411→  endDate: string,
   412→  limit: number,
   413→  config: CategoryConfiguration,
   414→  dryRun: boolean
   415→): Promise<ProcessingSummary> {
   416→  const summary: ProcessingSummary = {
   417→    totalEmails: 0,
   418→    success: 0,
   419→    errors: 0,
   420→    totalDurationMs: 0,
   421→    errorDetails: [],
   422→  };
   423→
   424→  const startTime = Date.now();
   425→
   426→  try {
   427→    // Parse and validate dates
   428→    const start = new Date(startDate);
   429→    const end = new Date(endDate);
   430→
   431→    // Validate dates are valid
   432→    if (isNaN(start.getTime()) || isNaN(end.getTime())) {
   433→      throw new Error('Invalid date format. Use YYYY-MM-DD format for dates');
   434→    }
   435→
   436→    if (start > end) {
   437→      throw new Error('Invalid date range: start date must be before end date');
   438→    }
   439→
   440→    // 1. Fetch emails by date range
   441→    console.log(`Fetching emails from ${startDate} to ${endDate} (limit: ${limit})...`);
   442→    const emails = await fetchEmailsByDateRange(start, end, limit);
   443→
   444→    summary.totalEmails = emails.length;
   445→    console.log(`Found ${emails.length} emails to process\n`);
   446→
   447→    if (emails.length === 0) {
   448→      console.log('No emails found in date range.');
   449→      summary.totalDurationMs = Date.now() - startTime;
   450→      return summary;
   451→    }
   452→
   453→    // 2. Initialize pipeline
   454→    const pipeline = new ClassificationPipeline(config);
   455→
   456→    // 3. Process each email
   457→    for (const email of emails) {
   458→      try {
   459→        console.log(`Classifying [${email.id}] ${email.subject}`);
   460→        const result = await pipeline.classify(email);
   461→
   462→        console.log(formatEmailOutput(email, result));
   463→
   464→        if (!dryRun) {
   465→          await saveClassificationResult(email.id, result);
   466→        }
   467→
   468→        await writeExplainabilityTrace(email, result);
   469→
   470→        summary.success++;
   471→      } catch (error) {
   472→        summary.errors++;
   473→        summary.errorDetails.push({
   474→          messageId: email.id,
   475→          error: error instanceof Error ? error.message : String(error),
   476→        });
   477→
   478→        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
   479→      }
   480→    }
   481→
   482→    summary.totalDurationMs = Date.now() - startTime;
   483→  } catch (error) {
   484→    console.error(`Fatal error in date range processing: ${error instanceof Error ? error.message : String(error)}`);
   485→    throw error;
   486→  }
   487→
   488→  return summary;
   489→}
   490→
   491→/**
   492→ * Format per-email output line
   493→ *
   494→ * @param email - Email message
   495→ * @param result - Classification result
   496→ * @returns Formatted output string
   497→ */
   498→export function formatEmailOutput(email: EmailMessage, result: ClassificationResult): string {
   499→  const labels = result.selectedLabels.map((label) => label.subtype || label.category).join(', ');
   500→  const primaryLabel = result.selectedLabels.find((l) => l.isPrimary);
   501→  const confidence = primaryLabel ? primaryLabel.confidence.toFixed(2) : '0.00';
   502→  const durationSec = (result.processingDurationMs / 1000).toFixed(1);
   503→
   504→  return `[${email.id}] ${email.subject} → labels: [${labels || 'none'}] (confidence: ${confidence}) - ${durationSec}s`;
   505→}
   506→
   507→/**
   508→ * Format summary statistics
   509→ *
   510→ * @param summary - Processing summary
   511→ * @returns Formatted summary string
   512→ */
   513→export function formatSummary(summary: ProcessingSummary): string {
   514→  const totalSec = (summary.totalDurationMs / 1000).toFixed(1);
   515→  const avgSec = summary.totalEmails > 0 ? (summary.totalDurationMs / 1000 / summary.totalEmails).toFixed(2) : '0.00';
   516→
   517→  let output = `\n${'='.repeat(80)}\n`;
   518→  output += `Processed ${summary.totalEmails} emails in ${totalSec}s (avg ${avgSec}s/email)\n`;
   519→  output += `${summary.success} success, ${summary.errors} errors\n`;
   520→
   521→  if (summary.errorDetails.length > 0) {
   522→    output += '\nErrors:\n';
   523→    for (const error of summary.errorDetails) {
   524→      output += `  - [${error.messageId}] ${error.error}\n`;
   525→    }
   526→  }
   527→
   528→  output += `${'='.repeat(80)}\n`;
   529→
   530→  return output;
   531→}
   532→
   533→/**
   534→ * Write explainability trace to file
   535→ *
   536→ * @param email - Email message
   537→ * @param result - Classification result
   538→ * @returns Path to written trace file
   539→ */
   540→export async function writeExplainabilityTrace(email: EmailMessage, result: ClassificationResult): Promise<string> {
   541→  // Find monorepo root for consistent output location
   542→  const repoRoot = await findRepoRoot();
   543→
   544→  // Create timestamped output directory
   545→  const timestamp = new Date().toISOString().replace(/[:.]/g, '-').split('.')[0].replace('T', '-');
   546→  const outputDir = join(repoRoot, 'test-pipeline-results', timestamp);
   547→
   548→  await fs.mkdir(outputDir, { recursive: true });
   549→
   550→  // Write trace JSON
   551→  const tracePath = join(outputDir, `${email.id}.json`);
   552→  const trace = {
   553→    messageId: email.id,
   554→    subject: email.subject,
   555→    from: email.from.email,
   556→    date: email.date,
   557→    classificationResult: result,
   558→    timestamp: new Date().toISOString(),
   559→  };
   560→
   561→  await fs.writeFile(tracePath, JSON.stringify(trace, null, 2));
   562→
   563→  return tracePath;
   564→}
   565→
   566→/**
   567→ * Main CLI entry point
   568→ *
   569→ * @param args - Command line arguments
   570→ * @returns Exit code (0 = success, 1 = error)
   571→ */
   572→export async function runTestPipeline(args: string[]): Promise<number> {
   573→  try {
   574→    // 1. Parse arguments
   575→    const cliArgs = parseArguments(args);
   576→
   577→    console.log(`\nTest Pipeline - Mode: ${cliArgs.mode}${cliArgs.dryRun ? ' [DRY RUN]' : ''}\n`);
   578→
   579→    // 2. Load configuration
   580→    console.log('Loading configuration...');
   581→    const config = await loadConfiguration();
   582→    console.log('Configuration loaded successfully\n');
   583→
   584→    // 3. Process based on mode
   585→    let summary: ProcessingSummary;
   586→
   587→    switch (cliArgs.mode) {
   588→      case 'single':
   589→        summary = await processSingleEmail(cliArgs.messageId!, config, cliArgs.dryRun);
   590→        break;
   591→
   592→      case 'batch':
   593→        summary = await processBatchEmails(cliArgs.limit || 10, config, cliArgs.dryRun);
   594→        break;
   595→
   596→      case 'date-range':
   597→        summary = await processDateRangeEmails(
   598→          cliArgs.startDate!,
   599→          cliArgs.endDate!,
   600→          cliArgs.limit || 100,
   601→          config,
   602→          cliArgs.dryRun
   603→        );
   604→        break;
   605→    }
   606→
   607→    // 4. Print summary
   608→    console.log(formatSummary(summary));
   609→
   610→    // 5. Cleanup
   611→    await closeQueryPool();
   612→    await closeWriterPool();
   613→
   614→    // 6. Return exit code
   615→    return summary.errors > 0 ? 1 : 0;
   616→  } catch (error) {
   617→    console.error(`\nFatal error: ${error instanceof Error ? error.message : String(error)}`);
   618→
   619→    // Cleanup on error
   620→    try {
   621→      await closeQueryPool();
   622→      await closeWriterPool();
   623→    } catch {
   624→      // Ignore cleanup errors
   625→    }
   626→
   627→    return 1;
   628→  }
   629→}
   630→
   631→/**
   632→ * CLI execution (only when run directly)
   633→ */
   634→if (require.main === module) {
   635→  runTestPipeline(process.argv.slice(2))
   636→    .then((exitCode) => {
   637→      process.exit(exitCode);
   638→    })
   639→    .catch((error) => {
   640→      console.error('Unexpected error:', error);
   641→      process.exit(1);
   642→    });
   643→}
