     1→/**
     2→ * Classification Pipeline Orchestrator
     3→ *
     4→ * Orchestrates the complete 9-stage classification pipeline with canonical signatures:
     5→ * (email, session, result, config) => void
     6→ *
     7→ * Pipeline Stages:
     8→ * 1. Hard Assertions - Domain-based high-confidence categorization
     9→ * 2. Strong Indicators - Weighted seed scoring with diminishing returns
    10→ * 3. Rule Scoring - Hierarchical pattern matching (high/medium/low tiers)
    11→ * 4. Attribute Detection - Cross-cutting signals (urgency, domains, structural patterns)
    12→ * 5. Attribute Influence - Role-based bonuses (CORE, PRIMARY_BOOST, etc.)
    13→ * 6. Disambiguation - Pairwise conflict resolution for close scores
    14→ * 7. Multi-label Selection - Confidence-based label assignment with co-presence rules
    15→ * 8. AI Routing - Selective AI classification for uncertain cases
    16→ * 9. Final Decision - Label assignment and action determination
    17→ * 10. Audit Trail - Complete explainability trace generation
    18→ */
    19→
    20→import { EmailMessage } from '../types/email-message';
    21→import { CategoryConfiguration } from '../types/category-configuration';
    22→import { ClassificationResult } from '../types/classification-result';
    23→
    24→// Validation utilities
    25→import { validateEmailInput, validateConfigInput } from '../utils/validation';
    26→
    27→// Initialization utilities
    28→import {
    29→  createClassificationSession,
    30→  createClassificationResult,
    31→  incrementSessionSuccess,
    32→  incrementSessionError,
    33→  finalizeClassificationSession,
    34→} from '../utils/initialization';
    35→
    36→// Pipeline stages (canonical signatures)
    37→import { executeHardAssertions } from '../stages/hard-assertions';
    38→import { executeStrongIndicators } from '../stages/strong-indicators';
    39→import { executeRuleScoring } from '../stages/rule-scoring';
    40→import { executeAttributeDetection } from '../stages/attribute-detection';
    41→import { executeAttributeInfluence } from '../stages/attribute-influence';
    42→import { executeDisambiguation } from '../stages/disambiguation';
    43→import { executeMultiLabelSelection } from '../stages/multi-label-selection';
    44→
    45→// Stage-specific config types
    46→import type { HardAssertionStageConfig } from '../stages/hard-assertions';
    47→import type { StrongIndicatorStageConfig } from '../stages/strong-indicators';
    48→import type { RuleScoringStageConfig } from '../stages/rule-scoring';
    49→import type { AttributeDetectionStageConfig } from '../stages/attribute-detection';
    50→import type { MultiLabelConfig, ConfidenceThresholds } from '../stages/types';
    51→
    52→/**
    53→ * Error result for batch processing when individual email fails
    54→ */
    55→export interface ClassificationErrorResult {
    56→  error: Error;
    57→  emailId: string;
    58→  processingDurationMs: number;
    59→}
    60→
    61→/**
    62→ * Classification Pipeline orchestrator
    63→ *
    64→ * Manages sequential execution of classification stages with proper context
    65→ * propagation, error handling, and performance tracking.
    66→ */
    67→export class ClassificationPipeline {
    68→  private readonly config: CategoryConfiguration;
    69→
    70→  /**
    71→   * Initialize classification pipeline with validated configuration
    72→   *
    73→   * @param config - Complete category configuration including processingConfig
    74→   * @throws {Error} If configuration validation fails
    75→   */
    76→  constructor(config: CategoryConfiguration) {
    77→    // Validate processing configuration
    78→    validateConfigInput(config.processingConfig);
    79→
    80→    // Validate confidence thresholds specifically
    81→    const { confidenceThresholds } = config.processingConfig;
    82→    if (
    83→      !confidenceThresholds ||
    84→      confidenceThresholds.highConfidence < 0 ||
    85→      confidenceThresholds.mediumConfidence < 0 ||
    86→      confidenceThresholds.lowConfidence < 0 ||
    87→      confidenceThresholds.secondaryLabelMinGap < 0
    88→    ) {
    89→      throw new Error('Invalid confidence thresholds: all values must be non-negative');
    90→    }
    91→
    92→    this.config = config;
    93→  }
    94→
    95→  /**
    96→   * Get configuration (for testing and future stage integration)
    97→   */
    98→  getConfig(): CategoryConfiguration {
    99→    return this.config;
   100→  }
   101→
   102→  /**
   103→   * Extract configuration for hard assertions stage
   104→   */
   105→  private getHardAssertionConfig(): HardAssertionStageConfig {
   106→    return {
   107→      confidenceThresholds: this.config.processingConfig.confidenceThresholds,
   108→      categorySignals: this.config.processingConfig.categorySignals as never, // TODO: Fix type mismatch in Phase 3.6
   109→      domainLookup: {}, // TODO: Implement domain resolution in Phase 3.6
   110→    };
   111→  }
   112→
   113→  /**
   114→   * Extract configuration for strong indicators stage
   115→   */
   116→  private getStrongIndicatorConfig(): StrongIndicatorStageConfig {
   117→    return {
   118→      confidenceThresholds: this.config.processingConfig.confidenceThresholds,
   119→      categorySignals: this.config.processingConfig.categorySignals as never, // TODO: Fix type mismatch in Phase 3.6
   120→      domainLookup: {}, // TODO: Implement domain resolution in Phase 3.6
   121→      strongIndicatorBaseWeight: 10, // TODO: Extract from config in Phase 3.6
   122→      diminishingReturnsFactor: 0.5, // TODO: Extract from config in Phase 3.6
   123→    };
   124→  }
   125→
   126→  /**
   127→   * Extract configuration for rule scoring stage
   128→   */
   129→  private getRuleScoringConfig(): RuleScoringStageConfig {
   130→    return {
   131→      topLevelCategories: this.config.processingConfig.topLevelCategories,
   132→      settings: this.config.processingConfig.settings.ruleScoring,
   133→      tuningParameters: {
   134→        K_high: 5, // TODO: Extract from config in Phase 3.6
   135→        K_medium: 10, // TODO: Extract from config in Phase 3.6
   136→        K_low: 15, // TODO: Extract from config in Phase 3.6
   137→        M_medium: 0.7, // TODO: Extract from config in Phase 3.6
   138→        M_low: 0.3, // TODO: Extract from config in Phase 3.6
   139→        TAIL_DAMPEN: 0.5, // TODO: Extract from config in Phase 3.6
   140→        TAIL_RATIO_CAP: 0.25, // TODO: Extract from config in Phase 3.6
   141→      },
   142→    };
   143→  }
   144→
   145→  /**
   146→   * Extract configuration for attribute detection stage
   147→   */
   148→  private getAttributeDetectionConfig(): AttributeDetectionStageConfig {
   149→    return {
   150→      attributes: this.config.processingConfig.attributes,
   151→      settings: {
   152→        attributeProcessing: this.config.processingConfig.settings.attributeProcessing,
   153→      },
   154→      performanceCache: {}, // Optional performance cache for domain lookups
   155→    };
   156→  }
   157→
   158→  /**
   159→   * Extract configuration for multi-label selection stage
   160→   */
